/* ============================================================
   SAEP Analytics — boletim-print.js  (versão limpa)
   Layout SENAI/SAEP — A5 paisagem — 1 página
============================================================ */

const SENAI_LOGO_SRC = 'data:image/jpeg;base64,'

/* ---- cores ---- */
function bpColor(p){
    if(p>=80) return '#16a34a';
    if(p>=60) return '#2563eb';
    if(p>=40) return '#d97706';
    return '#dc2626';
}
function bpLabel(p){
    if(p>=80) return {t:'DESTAQUE POSITIVO',          c:'#16a34a',bg:'#f0fdf4'};
    if(p>=60) return {t:'NÍVEL REGULAR',              c:'#d97706',bg:'#fffbeb'};
    if(p>=40) return {t:'NECESSIDADE DE REVISÃO',     c:'#d97706',bg:'#fef3c7'};
    return          {t:'DESTAQUE CRÍTICO',            c:'#dc2626',bg:'#fee2e2'};
}

/* ---- semicírculo ---- */
function bpSVG(p, color) {
    const r = 18, c = Math.PI * r, off = c - (p / 100) * c;
    return `<svg width="44" height="26" viewBox="0 0 44 26" style="display:block;">
        <path d="M4,23 A18,18 0 0 1 40,23" fill="none" stroke="#e2e8f0" stroke-width="4" stroke-linecap="round"/>
        <path d="M4,23 A18,18 0 0 1 40,23" fill="none" stroke="${color}" stroke-width="4" stroke-linecap="round"
              stroke-dasharray="${c}" stroke-dashoffset="${off}"/>
        <text x="22" y="20" text-anchor="middle" font-family="Inter,Arial,sans-serif"
              font-size="7" font-weight="800" fill="${color}">${p}%</text>
    </svg>`;
}

/* ---- conhecimentos ---- */
function bpKnow(nome, cap){
    const recs = ApplicationState.answerRecords.filter(
        r => r.aluno===nome && r.cap===cap && r.conhecimento);
    if(!recs.length) return '<span style="color:#94a3b8;font-size:5px;">Sem registros</span>';
    const map={};
    recs.forEach(r=>{
        if(!map[r.conhecimento]) map[r.conhecimento]={ac:0,tot:0};
        map[r.conhecimento].tot++;
        if(r.acertou) map[r.conhecimento].ac++;
    });
    return Object.entries(map).map(([n,m])=>{
        const p=Math.round(m.ac/m.tot*100), c=bpColor(p);
        const ic=m.ac===m.tot?'✓':p===0?'✗':'~';
        const icc=m.ac===m.tot?'#16a34a':p===0?'#dc2626':'#d97706';
        const sn=n.length>28?n.slice(0,26)+'…':n;
        return `<div style="display:grid;grid-template-columns:8px 1fr 24px;gap:2px;font-size:5.5px;line-height:1.4;margin-bottom:1px;">
            <span style="color:${icc};font-weight:800;">${ic}</span>
            <span style="color:#334155;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${sn}</span>
            <span style="font-weight:800;color:${c};text-align:right;">${p}%</span>
        </div>`;
    }).join('');
}

/* ---- diagnóstico pedagógico ---- */
function bpDiagnostico(s) {
    const level   = getStudentSaepLevel(s);
    const lcolor  = getLevelColor(level);
    const capPerf = calculateStudentCapacityPerformance(s.nome);
    const knwPerf = calculateStudentKnowledgePerformance(s.nome);

    const capExtremes = getPerformanceExtremes(capPerf.labels, capPerf.values);
    const knwExtremes = knwPerf.labels.length
        ? getPerformanceExtremes(knwPerf.labels, knwPerf.values)
        : null;

    const interpretacoes = {
        'Avançado':         'Domínio consistente das capacidades avaliadas. Potencial para aprofundamento e resolução de situações mais complexas.',
        'Adequado':         'Desempenho satisfatório com domínio funcional da maior parte das capacidades. Pontos específicos a consolidar.',
        'Básico':           'Domínio parcial das capacidades avaliadas. Necessidade de consolidação mais sistemática dos conteúdos.',
        'Abaixo do Básico': 'Dificuldades relevantes nas capacidades avaliadas. Necessita intervenção pedagógica mais intensiva e acompanhamento frequente.'
    };

    const encaminhamentos = {
        'Avançado':         'Propor atividades de ampliação, problemas desafiadores e aplicações integradoras.',
        'Adequado':         'Reforçar os pontos de menor desempenho com atividades direcionadas. Manter desafios graduais.',
        'Básico':           'Retomada orientada dos conteúdos essenciais com exercícios progressivos e mediação próxima.',
        'Abaixo do Básico': 'Retomada dos fundamentos, atividades guiadas e acompanhamento contínuo com foco em pequenas evoluções.'
    };

    function linha(cor, titulo, texto) {
        return `<div style="display:flex;gap:5px;margin-bottom:3px;align-items:flex-start;">
            <span style="width:7px;height:7px;border-radius:50%;background:${cor};flex-shrink:0;margin-top:1px;"></span>
            <div style="font-size:6px;line-height:1.4;">
                <strong style="color:#1e3a8a;">${titulo}:</strong>
                <span style="color:#334155;"> ${texto}</span>
            </div>
        </div>`;
    }

    let linhas = '';

    // Leitura pedagógica
    linhas += linha(lcolor, 'Leitura pedagógica', interpretacoes[level] || level);

    // Capacidade mais forte e mais fraca
    if (capExtremes) {
        const melhor = `${capExtremes.best.label} — ${getCapacityDisplayName(capExtremes.best.label)} (${capExtremes.best.value}%)`;
        const fraca  = `${capExtremes.worst.label} — ${getCapacityDisplayName(capExtremes.worst.label)} (${capExtremes.worst.value}%)`;
        linhas += linha('#16a34a', 'Ponto mais forte', melhor);
        linhas += linha('#dc2626', 'Ponto crítico em capacidade', fraca);
    }

    // Conhecimentos extremos
    if (knwExtremes) {
        const kMelhor = `${knwExtremes.best.label} (${knwExtremes.best.value}%)`;
        const kFraco  = `${knwExtremes.worst.label} (${knwExtremes.worst.value}%)`;
        linhas += linha('#7c3aed', 'Conhecimento com melhor resultado', kMelhor);
        linhas += linha('#dc2626', 'Conhecimento que mais exige reforço', kFraco);
    }

    // Encaminhamento da capacidade mais fraca
    if (capExtremes) {
        const guia = getCapacityPedagogicalGuidance(capExtremes.worst.label);
        if (guia) linhas += linha('#d97706', 'Encaminhamento prioritário', guia);
    }

    // Estratégia geral
    linhas += linha(lcolor, 'Estratégia recomendada', encaminhamentos[level] || '');

    return `<div style="border:1px solid ${lcolor};border-left:3px solid ${lcolor};border-radius:4px;
                        padding:5px 7px;margin-bottom:4px;background:#f8fafc;">
        <div style="font-size:6px;font-weight:800;text-transform:uppercase;
                    letter-spacing:0.05em;color:#1e3a8a;margin-bottom:4px;">
            Diagnóstico Pedagógico — ${level}
        </div>
        ${linhas}
    </div>`;
}


function bpCard(nome, cap, perf){
    const color=bpColor(perf), lb=bpLabel(perf);
    const capName=getCapacityDisplayName(cap).toUpperCase();
    return `<div style="border:1px solid #e2e8f0;border-radius:5px;overflow:hidden;
                        background:#fff;display:flex;flex-direction:column;
                        break-inside:avoid;page-break-inside:avoid;">
        <div style="background:#1e3a8a;padding:3px 5px;">
            <span style="font-size:5.5px;font-weight:800;color:#fff;">${cap} ${capName} (${perf}%)</span>
        </div>
        <div style="display:flex;gap:5px;padding:4px 6px;flex:1;align-items:flex-start;">
            <div style="flex-shrink:0;padding-top:1px;">${bpSVG(perf,color)}</div>
            <div style="flex:1;min-width:0;">
                <div style="font-size:5px;font-weight:800;color:#64748b;text-transform:uppercase;
                            letter-spacing:0.05em;margin-bottom:3px;">Subf/Conhec</div>
                ${bpKnow(nome,cap)}
            </div>
        </div>
        <div style="font-size:5.5px;font-weight:800;text-align:center;padding:2px 4px;
                    text-transform:uppercase;letter-spacing:0.03em;
                    color:${lb.c};background:${lb.bg};">${lb.t}</div>
    </div>`;
}

/* ---- HTML completo ---- */
function buildBoletimHtml(s){
    const level=getStudentSaepLevel(s);
    const lcolor=getLevelColor(level);
    const course=(getSelectedCourseConfig()?.nome||'').toUpperCase();
    const today=new Date().toLocaleDateString('pt-BR');
    const mat=s.matricula||'--';
    const capPerf=calculateStudentCapacityPerformance(s.nome);
    const cards=capPerf.labels.map((c,i)=>bpCard(s.nome,c,capPerf.values[i])).join('');
    const total=(s.acertos||0)+(s.erros||0);
    const acW=total>0?Math.round(s.acertos/total*100):0;
    const erW=total>0?Math.round(s.erros/total*100):0;
    const desemp=Number(s.desempenho||0).toFixed(1);

    /* Grid de capacidades: 3 colunas */
    return `
    <div style="font-family:Inter,Arial,sans-serif;background:#fff;color:#0f172a;
                font-size:7px;width:100%;box-sizing:border-box;">

        <!-- HEADER -->
        <div style="display:flex;justify-content:space-between;align-items:center;
                    background:#1e3a8a;color:#fff;padding:4px 8px;
                    border-radius:4px 4px 0 0;margin-bottom:4px;gap:8px;">
            <div style="display:flex;align-items:center;gap:8px;flex:1;">
                <div style="background:#fff;border-radius:3px;padding:2px 5px;flex-shrink:0;">
                    <img src="${SENAI_LOGO_SRC}" style="height:26px;width:auto;display:block;" alt="SENAI">
                </div>
                <div style="display:flex;flex-direction:column;gap:1px;">
                    <span style="font-size:5.5px;font-weight:600;color:#bfdbfe;letter-spacing:0.04em;text-transform:uppercase;">
                        SENAI-CE · CETAFR — Alexandre Figueira Rodrigues
                    </span>
                    <span style="font-size:6.5px;font-weight:800;letter-spacing:0.02em;">
                        PAINEL DIDÁTICO DE DESEMPENHO INDIVIDUAL — ${s.nome.toUpperCase()}
                    </span>
                </div>
            </div>
            <span style="font-size:6px;color:#bfdbfe;white-space:nowrap;">${mat} · ${today}</span>
        </div>

        <!-- KPIs -->
        <div style="display:grid;grid-template-columns:1.3fr 0.9fr 1fr 1fr 1fr 1.2fr;
                    gap:3px;margin-bottom:4px;">
            <div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:4px;padding:3px 5px;">
                <div style="font-size:5px;font-weight:800;text-transform:uppercase;color:#64748b;margin-bottom:1px;">Desempenho individual</div>
                <div style="font-size:13px;font-weight:800;color:${lcolor};line-height:1.1;">${desemp}%</div>
            </div>
            <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:4px;padding:3px 5px;">
                <div style="font-size:5px;font-weight:800;text-transform:uppercase;color:#64748b;margin-bottom:1px;">Questões totais</div>
                <div style="font-size:13px;font-weight:800;line-height:1.1;">${total||'--'}</div>
            </div>
            <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:4px;padding:3px 5px;">
                <div style="font-size:5px;font-weight:800;text-transform:uppercase;color:#64748b;margin-bottom:1px;">Acertos</div>
                <div style="font-size:13px;font-weight:800;color:#16a34a;line-height:1.1;">${s.acertos||0}</div>
                <div style="height:3px;background:#e2e8f0;border-radius:999px;overflow:hidden;margin-top:2px;">
                    <div style="height:100%;width:${acW}%;background:#16a34a;"></div></div>
            </div>
            <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:4px;padding:3px 5px;">
                <div style="font-size:5px;font-weight:800;text-transform:uppercase;color:#64748b;margin-bottom:1px;">Erros</div>
                <div style="font-size:13px;font-weight:800;color:#dc2626;line-height:1.1;">${s.erros||0}</div>
                <div style="height:3px;background:#e2e8f0;border-radius:999px;overflow:hidden;margin-top:2px;">
                    <div style="height:100%;width:${erW}%;background:#dc2626;"></div></div>
            </div>
            <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:4px;padding:3px 5px;">
                <div style="font-size:5px;font-weight:800;text-transform:uppercase;color:#64748b;margin-bottom:1px;">Tempo de realização</div>
                <div style="font-size:9px;font-weight:800;line-height:1.2;">${s.tempo||'--'}</div>
            </div>
            <div style="background:#f8fafc;border:1px solid ${lcolor};border-radius:4px;padding:3px 5px;">
                <div style="font-size:5px;font-weight:800;text-transform:uppercase;color:#64748b;margin-bottom:1px;">Nível SAEP</div>
                <div style="font-size:7.5px;font-weight:800;color:${lcolor};line-height:1.2;">${level}</div>
                <div style="font-size:4.5px;color:#64748b;margin-top:1px;">${course}</div>
            </div>
        </div>

        <!-- CARDS DE CAPACIDADE -->
        <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:3px;margin-bottom:4px;">
            ${cards}
        </div>

        <!-- DIAGNÓSTICO PEDAGÓGICO -->
        ${bpDiagnostico(s)}
    </div>`;
}

/* ---- estilos de impressão ---- */
function injectPrintStyles(){
    if(document.getElementById('bp-print-styles')) return;
    const s=document.createElement('style');
    s.id='bp-print-styles';
    s.textContent=`
        #boletimSenaiPrint { display:none; }
        @media print {
            @page { size:A5 landscape; margin:3mm 4mm; }
            body > * { display:none !important; }
            #boletimSenaiPrint { display:block !important; }
            * { -webkit-print-color-adjust:exact !important; print-color-adjust:exact !important; box-sizing:border-box; }
            #boletimSenaiPrint > div { page-break-inside:avoid; }
        }`;
    document.head.appendChild(s);
}

/* ---- função pública ---- */
function printBoletimSenai(s){
    if(!s){ alert('Selecione um aluno antes de imprimir.'); return; }
    injectPrintStyles();
    let el=document.getElementById('boletimSenaiPrint');
    if(!el){ el=document.createElement('div'); el.id='boletimSenaiPrint'; document.body.appendChild(el); }
    el.innerHTML=buildBoletimHtml(s);
    window.print();
}
